#[cfg(test)]
mod tests {
    use super::*;

    fn registry(name: &str) -> &'static TagRegistry {
        TAGS.iter().find(|r| r.registry == name).expect("registry present")
    }

    fn tag(reg: &str, name: &str) -> &'static Tag {
        registry(reg).tags.iter().find(|t| t.name == name).expect("tag present")
    }

    /// Pin a spread of block ids that sit *after* the collection-registered
    /// members (`ColorCollection` ×16, `WeatheringCopperCollection` ×8) — the
    /// exact slots the old generator mis-counted. Diamond ore is the first
    /// member of `diamond_ores`; the low ids stay anchored to terrain.
    #[test]
    fn block_ids_pin_post_collection_checkpoints() {
        assert_eq!(tag("minecraft:block", "minecraft:dirt").ids[0], 9);
        assert_eq!(tag("minecraft:block", "minecraft:iron_ores").ids[0], 44);
        assert_eq!(tag("minecraft:block", "minecraft:diamond_ores").ids[0], 203);
        assert_eq!(tag("minecraft:block", "minecraft:copper_ores").ids[0], 1042);
    }

    /// Same idea for items: anvil/arrow/wooden_sword all sit past the first
    /// item collection and were shifted before the fix.
    #[test]
    fn item_ids_pin_post_collection_checkpoints() {
        assert_eq!(tag("minecraft:item", "minecraft:diamond_ores").ids[0], 105);
        assert_eq!(tag("minecraft:item", "minecraft:anvil").ids[0], 506);
        assert_eq!(tag("minecraft:item", "minecraft:arrows").ids[0], 923);
        assert!(tag("minecraft:item", "minecraft:swords").ids.contains(&939));
    }

    /// The family tags whose members are *all* collection-registered were
    /// wrongly empty under the old generator. Guard their cardinality so a
    /// regression can't silently blank them again.
    #[test]
    fn collection_family_tags_are_populated() {
        assert_eq!(tag("minecraft:block", "minecraft:wool").ids.len(), 16);
        assert_eq!(tag("minecraft:block", "minecraft:banners").ids.len(), 32);
        assert_eq!(tag("minecraft:block", "minecraft:beds").ids.len(), 16);
        assert_eq!(tag("minecraft:block", "minecraft:concrete").ids.len(), 16);
        assert_eq!(tag("minecraft:block", "minecraft:copper").ids.len(), 8);
        assert_eq!(tag("minecraft:item", "minecraft:wool").ids.len(), 16);
        assert_eq!(tag("minecraft:item", "minecraft:banners").ids.len(), 16);
        assert_eq!(tag("minecraft:item", "minecraft:dyes").ids.len(), 16);
    }
}
